def dedup_report(rows, key='id'):
    seen = {}
    unique = []
    conflicts = []
    for row in rows:
        k = row[key]
        if k not in seen:
            seen[k] = row
            unique.append(row)
        else:
            if row != seen[k]:
                conflicts.append({'key': k, 'prev': seen[k], 'new': row})
    return {'unique': unique, 'conflicts': conflicts}

rows = [
    {'id': 'C001', 'payload': 1},
    {'id': 'C002', 'payload': 2},
    {'id': 'C001', 'payload': 9},
]
print(dedup_report(rows))

