def get_nested(d, *keys, default=None):
    cur = d
    for k in keys:
        if not isinstance(cur, dict) or k not in cur:
            return default
        cur = cur[k]
    return cur

profile = {'profile': {'phone': '999'}}
print(get_nested(profile, 'profile', 'phone'))
print(get_nested(profile, 'profile', 'email', default='N/A'))

